	/* 상품 자동 증가 코드 */
	SELECT 
		CASE 
		WHEN count(*) = 0 THEN 'prod_1'
		ELSE
			CONCAT(
				 'prod_'
				,MAX(CAST(SUBSTRING_INDEX(p.prod_cd, 'prod_', -1) AS UNSIGNED)) + 1
			)
		END AS newCode
	FROM 
		products p

